mapper.select:
SELECT sf.id, sf.location, sf.file_size AS fileSize, sf.original_name AS originalName, sf.create_time AS createTime, su.nickname AS createBy FROM sys_file sf LEFT JOIN sys_user su ON sf.create_by = su.id WHERE sf.del_flag = '0'
AND sf.original_name like #{request.keyword}
ORDER BY sf.create_time DESC

SELECT sf.id, sf.location, sf.file_size AS fileSize, sf.original_name AS originalName, sf.create_time AS createTime, su.nickname AS createBy FROM sys_file sf LEFT JOIN sys_user su ON sf.create_by = su.id WHERE sf.del_flag = '0' AND sf.create_by = #{userId}
AND sf.original_name like #{request.keyword}
ORDER BY sf.create_time DESC
